   107→/**
   108→ * =============================
   109→ * QUIZ FUNCTIONALITY
   110→ * =============================
   111→ */
   112→
   113→function initQuiz() {
   114→	const questionElement = document.getElementById("question");
   115→	const optionsElement = document.getElementById("options");
   116→	const ctaButton = document.getElementById("quiz-cta");
   117→	const questionContainer = document.getElementsByClassName("question-container")[0];
   118→	const resultsContainer = document.getElementsByClassName("results-container")[0];
   119→	const progress = document.getElementsByClassName("progress")[0];
   120→	
   121→	if (!questionElement || !optionsElement || !questionContainer || !resultsContainer || !progress) {
   122→		return;
   123→	}
   124→	
   125→	let currentQuestion = 0;
   126→
   127→	function showQuestion() {
   128→		const question = quizData[currentQuestion];
   129→		questionContainer.classList.remove('question' + '-' + (question.id - 1));
   130→		questionContainer.classList.add('question' + '-' + question.id);
   131→		questionElement.innerHTML = question.title;
   132→		optionsElement.innerHTML = "";
   133→		
   134→		question.options.forEach(option => {
   135→			const button = document.createElement("button");
   136→			button.innerText = option.value;
   137→			button.classList.add('option-button', question.type);
   138→			button.setAttribute('data-answer', option.id);
   139→			
   140→			if (question.type === 'multi-select') {
   141→				ctaButton.style.display = 'block';
   142→				ctaButton.classList.add('disabled');
   143→				ctaButton.addEventListener("click", selectAnswer);
   144→				const checkbox = document.createElement("span");
   145→				checkbox.classList.add('checkbox');
   146→				button.insertBefore(checkbox, button.firstChild);
   147→				button.addEventListener("click", selectMulti);
   148→			} else {
   149→				ctaButton.style.display = 'none';
   150→				button.addEventListener("click", selectAnswer);
   151→			}
   152→			optionsElement.appendChild(button);
   153→		});
   154→	}
   155→
   156→	function selectMulti() {
   157→		if (this.classList.contains('selected')) {
   158→			this.classList.remove('selected');
   159→		} else {
   160→			this.classList.add('selected');
   161→		}
   162→
   163→		const noneOption = quizData[currentQuestion].options.length - 1;
   164→		let selectedElements = document.getElementsByClassName("selected");
   165→		
   166→		if (this.dataset.answer == noneOption) {
   167→			Array.from(selectedElements).forEach(element => {
   168→				if (element.dataset.answer != noneOption) {
   169→					element.classList.remove('selected');
   170→				}
   171→			});
   172→		} else {
   173→			Array.from(selectedElements).forEach(element => {
   174→				if (element.dataset.answer == noneOption) {
   175→					element.classList.remove('selected');
   176→				}
   177→			});
   178→		}
   179→
   180→		if (selectedElements.length > 0) {
   181→			ctaButton.classList.remove('disabled');
   182→		} else {
   183→			ctaButton.classList.add('disabled');
   184→		}
   185→	}
   186→
   187→	function bindClickEvents() {
   188→		let ctaButtons = document.getElementsByClassName('quiz-end-cta');
   189→		if (ctaButtons) {
   190→			Array.from(ctaButtons).forEach((button) => {
   191→				button.addEventListener("click", (e) => {
   192→					if (typeof trackQuizEvent === 'function') {
   193→						trackQuizEvent('last_question', e.target.innerText);
   194→					}
   195→				});
   196→			});
   197→		}
   198→	}
   199→
   200→	function selectAnswer(e) {
   201→		if (e.target.id === 'quiz-cta') {
   202→			const selectedElements = document.getElementsByClassName("selected");
   203→			let options = '';
   204→			if (selectedElements) {
   205→				Array.from(selectedElements).forEach((element, index) => {
   206→					options = options + element.innerText;
   207→					if (index !== selectedElements.length - 1) {
   208→						options += ', ';
   209→					}
   210→				});
   211→			}
   212→			if (typeof trackQuizEvent === 'function') {
   213→				trackQuizEvent('Q' + (currentQuestion + 1), options);
   214→			}
   215→		} else {
   216→			if (typeof trackQuizEvent === 'function') {
   217→				trackQuizEvent('Q' + (currentQuestion + 1), e.target.innerText);
   218→			}
   219→		}
   220→		
   221→		let answer = e.target.dataset.answer;
   222→		let width = progress.style.width.replace("%", "");
   223→		width = parseInt(width);
   224→		width = width + 17 + "%";
   225→		progress.style.width = width;
   226→
   227→		currentQuestion++;
   228→
   229→		if (currentQuestion < quizData.length) {
   230→			showQuestion();
   231→		} else {
   232→			resultsContainer.innerHTML +=
   233→				`<div>
   234→					<div class="results-content">
   235→						<h2>` + quizResultContent[answer].header + `</h2>
   236→						<p>` + quizResultContent[answer].body + `</p>
   237→					</div>
   238→					<div class="options-container">
   239→						<a href="#whats-included" class="btn quiz-end-cta">
   240→						I'm Ready To Start
   241→						</a>
   242→						<a href="#treatment-with-hone" class="option-button quiz-end-cta">
   243→						Still Thinking About it
   244→						</a>
   245→					</div>
   246→				</div>`;
   247→			bindClickEvents();
   248→			showResult();
   249→		}
   250→	}
   251→
   252→	function showResult() {
   253→		questionContainer.style.display = 'none';
   254→		resultsContainer.style.display = 'block';
   255→	}
   256→
   257→	showQuestion();
   258→}
