   260→/**
   261→ * =============================
   262→ * CAROUSELS INITIALIZATION
   263→ * =============================
   264→ */
   265→
   266→function initCarousels() {
   267→	if (typeof jQuery === 'undefined') {
   268→		return;
   269→	}
   270→
   271→	jQuery(document).ready(function($) {
   272→		// Reviews carousel
   273→		$('.carousel').slick({
   274→			slidesToShow: 3,
   275→			infinite: false,
   276→			slidesToScroll: 1,
   277→			dots: true,
   278→			arrows: true,
   279→			responsive: [
   280→				{
   281→					breakpoint: 768,
   282→					settings: {
   283→						slidesToShow: 1,
   284→						slidesToScroll: 1
   285→					}
   286→				},
   287→				{
   288→					breakpoint: 1280,
   289→					settings: {
   290→						slidesToShow: 2,
   291→						slidesToScroll: 1
   292→					}
   293→				}
   294→			]
   295→		});
   296→
   297→		// Product actions carousel
   298→		$('.product-actions-slick').slick({
   299→			slidesToShow: 4,
   300→			infinite: false,
   301→			slidesToScroll: 1,
   302→			dots: true,
   303→			arrows: true,
   304→			draggable: false,
   305→			responsive: [
   306→				{
   307→					breakpoint: 768,
   308→					settings: {
   309→						slidesToShow: 1,
   310→						slidesToScroll: 1,
   311→						infinite: true,
   312→					}
   313→				},
   314→				{
   315→					breakpoint: 1280,
   316→					settings: {
   317→						slidesToShow: 2,
   318→						slidesToScroll: 1
   319→					}
   320→				}
   321→			]
   322→		});
   323→	});
   324→}
   325→
   326→/**
   327→ * =============================
   328→ * ACCORDION FUNCTIONALITY
   329→ * =============================
   330→ */
   331→
   332→function initAccordion() {
   333→	const acc = document.getElementsByClassName("accordion-slide");
   334→
   335→	if (!acc || acc.length === 0) {
   336→		return;
   337→	}
   338→
   339→	const toggleAccordion = (e) => {
   340→		let target = e.currentTarget;
   341→		if (!target.classList.contains("active")) {
   342→			Array.from(acc).forEach((slide) => {
   343→				slide.classList.remove("active");
   344→				slide.children[1].style.display = "none";
   345→			});
   346→			target.classList.add("active");
   347→			target.children[1].style.display = "block";
   348→		} else {
   349→			target.classList.remove("active");
   350→			target.children[1].style.display = "none";
   351→		}
   352→	};
   353→
   354→	Array.from(acc).forEach((slide) => {
   355→		slide.addEventListener("click", (e) => toggleAccordion(e));
   356→	});
   357→}
   358→
   359→/**
   360→ * =============================
   361→ * REVIEWS EXPAND/COLLAPSE
   362→ * =============================
   363→ */
   364→
   365→function initReviewsExpand() {
   366→	const buttons = document.querySelectorAll('.quote-attribution');
   367→	
   368→	buttons.forEach(button => {
   369→		button.addEventListener('click', function() {
   370→			let dots = this.parentNode.querySelector('#dots');
   371→			let moreText = this.parentNode.querySelector('#more');
   372→			
   373→			if (dots && moreText) {
   374→				if (dots.style.display === "none") {
   375→					dots.style.display = "inline";
   376→					this.innerHTML = "Read more";
   377→					moreText.style.display = "none";
   378→				} else {
   379→					dots.style.display = "none";
   380→					this.innerHTML = "Read less";
   381→					moreText.style.display = "inline";
   382→				}
   383→			}
   384→		});
   385→	});
   386→}
   387→
   388→/**
   389→ * =============================
   390→ * INITIALIZATION
   391→ * =============================
   392→ */
   393→
   394→// Initialize quiz immediately
   395→initQuiz();
   396→
   397→// Initialize when DOM is ready
   398→if (document.readyState === 'loading') {
   399→	document.addEventListener('DOMContentLoaded', () => {
   400→		initCarousels();
   401→		initAccordion();
   402→		initReviewsExpand();
   403→	});
   404→} else {
   405→	initCarousels();
   406→	initAccordion();
   407→	initReviewsExpand();
   408→}
