   129→/**
   130→ * =============================
   131→ * QUIZ FUNCTIONALITY
   132→ * =============================
   133→ */
   134→
   135→function initQuiz() {
   136→	const questionElement = document.getElementById("question");
   137→	const optionsElement = document.getElementById("options");
   138→	const questionContainer = document.getElementsByClassName("question-container")[0];
   139→	const resultsContainer = document.getElementsByClassName("results-container")[0];
   140→	const progress = document.getElementsByClassName("progress")[0];
   141→	
   142→	if (!questionElement || !optionsElement || !questionContainer || !resultsContainer || !progress) {
   143→		return;
   144→	}
   145→	
   146→	let currentQuestion = 0;
   147→
   148→	function showQuestion() {
   149→		const question = quizData[currentQuestion];
   150→		questionContainer.classList.remove('question' + '-' + (question.id - 1));
   151→		questionContainer.classList.add('question' + '-' + question.id);
   152→		questionElement.innerText = question.title;
   153→		optionsElement.innerHTML = "";
   154→		
   155→		question.options.forEach(option => {
   156→			const button = document.createElement("button");
   157→			button.innerText = option.value;
   158→			button.classList.add('option-button', 'single-select');
   159→			button.setAttribute('data-answer', option.id);
   160→			optionsElement.appendChild(button);
   161→			button.addEventListener("click", selectAnswer);
   162→		});
   163→	}
   164→
   165→	function bindClickEvents() {
   166→		let ctaButtons = document.getElementsByClassName('quiz-end-cta');
   167→		if (ctaButtons) {
   168→			Array.from(ctaButtons).forEach((button) => {
   169→				button.addEventListener("click", (e) => {
   170→					if (typeof trackQuizEvent === 'function') {
   171→						trackQuizEvent('last_question', e.target.innerText);
   172→					}
   173→				});
   174→			});
   175→		}
   176→	}
   177→
   178→	function selectAnswer(e) {
   179→		if (typeof trackQuizEvent === 'function') {
   180→			trackQuizEvent('Q' + (currentQuestion + 1), e.target.innerText);
   181→		}
   182→		
   183→		let answer = e.target.dataset.answer;
   184→		let width = progress.style.width.replace("%", "");
   185→		width = parseInt(width);
   186→		width = width + 11.9 + "%";
   187→		progress.style.width = width;
   188→
   189→		currentQuestion++;
   190→
   191→		if (currentQuestion < quizData.length) {
   192→			showQuestion();
   193→		} else {
   194→			resultsContainer.innerHTML +=
   195→				`<div class="results-content">
   196→					<h2>` + quizResultContent[answer].header + `</h2>
   197→					<p>` + quizResultContent[answer].body + `</p>
   198→				</div>
   199→				<div class="options-container">
   200→					<a href="#whats-included" class="btn quiz-end-cta">
   201→					I'm Ready To Start
   202→					</a>
   203→					<a href="#treatment-with-hone" class="option-button quiz-end-cta">
   204→					Still Thinking About it
   205→					</a>
   206→				</div>`;
   207→			bindClickEvents();
   208→			showResult();
   209→		}
   210→	}
   211→
   212→	function showResult() {
   213→		questionContainer.style.display = 'none';
   214→		resultsContainer.style.display = 'flex';
   215→	}
   216→
   217→	showQuestion();
   218→}
