     1→/**
     2→ * Sticky CTA Utility
     3→ * ==================
     4→ * 
     5→ * HOW TO FIND THE RIGHT SCROLL TRIGGER VALUE:
     6→ * 1. Add temporary debug code to your page:
     7→ *    ```javascript
     8→ *    window.addEventListener('scroll', () => console.log('Scroll:', window.scrollY));
     9→ *    ```
    10→ * 2. Open browser DevTools console (F12)
    11→ * 3. Scroll to where you want the CTA to appear
    12→ * 4. Note the scroll position value
    13→ * 5. Use that value as scrollTrigger parameter
    14→ * 6. Remove the debug code
    15→ * 
    16→ * EXPORTS:
    17→ * - initStickyCTA(scrollTrigger, selector)
    18→ * 
    19→ * USAGE:
    20→ * ```javascript
    21→ * # Basic usage - show after scrolling 1340px
    22→ * initStickyCTA(1340);
    23→ * 
    24→ * # Custom selector
    25→ * initStickyCTA(2000, '.my-custom-banner');
    26→ * 
    27→ * # ES Module import
    28→ * import { initStickyCTA } from './utilities/stickyCTA.js';
    29→ * initStickyCTA(800);
    30→ * ```
    31→ * 
    32→ * @param {number} scrollTrigger - Scroll position (px) at which to show the sticky CTA
    33→ * @param {string} [selector='.stickycta-section'] - CSS selector for the sticky element
    34→ */
    35→function initStickyCTA(scrollTrigger, selector = '.stickycta-section') {
    36→	const stickyElement = document.querySelector(selector);
    37→
    38→	if (!stickyElement) {
    39→		console.warn(`Sticky CTA element not found: ${selector}`);
    40→		return;
    41→	}
    42→
    43→	function updateStickyState() {
    44→		const scrollPosition = window.scrollY;
    45→		const windowHeight = window.innerHeight;
    46→		const bodyHeight = document.body.offsetHeight;
    47→		const bannerHeight = stickyElement.offsetHeight;
    48→
    49→		// Hide when near bottom of page
    50→		if (scrollPosition + windowHeight >= bodyHeight - bannerHeight) {
    51→			stickyElement.classList.remove("show");
    52→		}
    53→		// Show when past scroll trigger
    54→		else if (scrollPosition > scrollTrigger) {
    55→			stickyElement.classList.add("show");
    56→		}
    57→		// Hide when above scroll trigger
    58→		else {
    59→			stickyElement.classList.remove("show");
    60→		}
    61→	}
    62→
    63→	// Add scroll listener
    64→	window.addEventListener("scroll", updateStickyState);
    65→
    66→	// Initial check
    67→	updateStickyState();
    68→}
    69→
    70→// Make function available globally (for non-bundled usage)
    71→if (typeof window !== 'undefined') {
    72→	window.initStickyCTA = initStickyCTA;
    73→}
    74→
    75→// ES module export (for bundled usage)
    76→export { initStickyCTA };
